    "content": "{"content":"// SPDX-License-Identifier: GPL-2.0\n#include <linux/pagewalk.h>\n#include <linux/highmem.h>\n#include <linux/sched.h>\n#include <linux/hugetlb.h>\n#include <linux/mmu_context.h>\n#include <linux/swap.h>\n\n#include <asm/tlbflush.h>\n\n#include \"internal.h\"\n\n/*\n * We want to know the real level where a entry is located ignoring any\n * folding of levels which may be happening. For example if p4d is folded then\n * a missing entry found at level 1 (p4d) is actually at level 0 (pgd).\n */\nstatic int real_depth(int depth)\n{\n\tif (depth == 3 && PTRS_PER_PMD == 1)\n\t\tdepth = 2;\n\tif (depth == 2 && PTRS_PER_PUD == 1)\n\t\tdepth = 1;\n\tif (depth == 1 && PTRS_PER_P4D == 1)\n\t\tdepth = 0;\n\treturn depth;\n}\n\nstatic int walk_pte_range_inner(pte_t *pte, unsigned long addr,\n\t\t\t\tunsigned long end, struct mm_walk *walk)\n{\n\tconst struct mm_walk_ops *ops = walk->ops;\n\tint err = 0;\n\n\tfor (;;) {\n\t\tif (ops->install_pte && pte_none(ptep_get(pte))) {\n\t\t\tpte_t new_pte;\n\n\t\t\terr = ops->install_pte(addr, addr + PAGE_SIZE, &new_pte,\n\t\t\t\t\t       walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\n\t\t\tset_pte_at(walk->mm, addr, pte, new_pte);\n\t\t\t/* Non-present before, so for arches that need it. */\n\t\t\tif (!WARN_ON_ONCE(walk->no_vma))\n\t\t\t\tupdate_mmu_cache(walk->vma, addr, pte);\n\t\t} else {\n\t\t\terr = ops->pte_entry(pte, addr, addr + PAGE_SIZE, walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t}\n\t\tif (addr >= end - PAGE_SIZE)\n\t\t\tbreak;\n\t\taddr += PAGE_SIZE;\n\t\tpte++;\n\t}\n\treturn err;\n}\n\nstatic int walk_pte_range(pmd_t *pmd, unsigned long addr, unsigned long end,\n\t\t\t  struct mm_walk *walk)\n{\n\tpte_t *pte;\n\tint err = 0;\n\tspinlock_t *ptl;\n\n\tif (walk->no_vma) {\n\t\t/*\n\t\t * pte_offset_map() might apply user-specific validation.\n\t\t * Indeed, on x86_64 the pmd entries set up by init_espfix_ap()\n\t\t * fit its pmd_bad() check (_PAGE_NX set and _PAGE_RW clear),\n\t\t * and CONFIG_EFI_PGT_DUMP efi_mm goes so far as to walk them.\n\t\t */\n\t\tif (walk->mm == &init_mm || addr >= TASK_SIZE)\n\t\t\tpte = pte_offset_kernel(pmd, addr);\n\t\telse\n\t\t\tpte = pte_offset_map(pmd, addr);\n\t\tif (pte) {\n\t\t\terr = walk_pte_range_inner(pte, addr, end, walk);\n\t\t\tif (walk->mm != &init_mm && addr < TASK_SIZE)\n\t\t\t\tpte_unmap(pte);\n\t\t}\n\t} else {\n\t\tpte = pte_offset_map_lock(walk->mm, pmd, addr, &ptl);\n\t\tif (pte) {\n\t\t\terr = walk_pte_range_inner(pte, addr, end, walk);\n\t\t\tpte_unmap_unlock(pte, ptl);\n\t\t}\n\t}\n\tif (!pte)\n\t\twalk->action = ACTION_AGAIN;\n\treturn err;\n}\n\nstatic int walk_pmd_range(pud_t *pud, unsigned long addr, unsigned long end,\n\t\t\t  struct mm_walk *walk)\n{\n\tpud_t pudval = pudp_get(pud);\n\tpmd_t *pmd;\n\tunsigned long next;\n\tconst struct mm_walk_ops *ops = walk->ops;\n\tbool has_handler = ops->pte_entry;\n\tbool has_install = ops->install_pte;\n\tint err = 0;\n\tint depth = real_depth(3);\n\n\t/*\n\t * For PTE handling, pte_offset_map_lock() takes care of checking\n\t * whether there actually is a page table. But it also has to be\n\t * very careful about concurrent page table reclaim. If we spot a PMD\n\t * table, it cannot go away, so we can just walk it. However, if we find\n\t * something else, we have to retry.\n\t */\n\tif (!pud_present(pudval) || pud_leaf(pudval)) {\n\t\twalk->action = ACTION_AGAIN;\n\t\treturn 0;\n\t}\n\n\tpmd = pmd_offset(pud, addr);\n\tdo {\nagain:\n\t\tnext = pmd_addr_end(addr, end);\n\t\tif (pmd_none(*pmd)) {\n\t\t\tif (has_install)\n\t\t\t\terr = __pte_alloc(walk->mm, pmd);\n\t\t\telse if (ops->pte_hole)\n\t\t\t\terr = ops->pte_hole(addr, next, depth, walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t\tif (!has_install)\n\t\t\t\tcontinue;\n\t\t}\n\n\t\twalk->action = ACTION_SUBTREE;\n\n\t\t/*\n\t\t * This implies that each ->pmd_entry() handler\n\t\t * needs to know about pmd_trans_huge() pmds\n\t\t */\n\t\tif (ops->pmd_entry)\n\t\t\terr = ops->pmd_entry(pmd, addr, next, walk);\n\t\tif (err)\n\t\t\tbreak;\n\n\t\tif (walk->action == ACTION_AGAIN)\n\t\t\tgoto again;\n\t\tif (walk->action == ACTION_CONTINUE)\n\t\t\tcontinue;\n\n\t\tif (!has_handler) { /* No handlers for lower page tables. */\n\t\t\tif (!has_install)\n\t\t\t\tcontinue; /* Nothing to do. */\n\t\t\t/*\n\t\t\t * We are ONLY installing, so avoid unnecessarily\n\t\t\t * splitting a present huge page.\n\t\t\t */\n\t\t\tif (pmd_present(*pmd) && pmd_trans_huge(*pmd))\n\t\t\t\tcontinue;\n\t\t}\n\n\t\tif (walk->vma)\n\t\t\tsplit_huge_pmd(walk->vma, pmd, addr);\n\t\telse if (pmd_leaf(*pmd) || !pmd_present(*pmd))\n\t\t\tcontinue; /* Nothing to do. */\n\n\t\terr = walk_pte_range(pmd, addr, next, walk);\n\t\tif (err)\n\t\t\tbreak;\n\n\t\tif (walk->action == ACTION_AGAIN)\n\t\t\tgoto again;\n\n\t} while (pmd++, addr = next, addr != end);\n\n\treturn err;\n}\n\nstatic int walk_pud_range(p4d_t *p4d, unsigned long addr, unsigned long end,\n\t\t\t  struct mm_walk *walk)\n{\n\tpud_t *pud;\n\tunsigned long next;\n\tconst struct mm_walk_ops *ops = walk->ops;\n\tbool has_handler = ops->pmd_entry || ops->pte_entry;\n\tbool has_install = ops->install_pte;\n\tint err = 0;\n\tint depth = real_depth(2);\n\n\tpud = pud_offset(p4d, addr);\n\tdo {\n again:\n\t\tnext = pud_addr_end(addr, end);\n\t\tif (pud_none(*pud)) {\n\t\t\tif (has_install)\n\t\t\t\terr = __pmd_alloc(walk->mm, pud, addr);\n\t\t\telse if (ops->pte_hole)\n\t\t\t\terr = ops->pte_hole(addr, next, depth, walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t\tif (!has_install)\n\t\t\t\tcontinue;\n\t\t}\n\n\t\twalk->action = ACTION_SUBTREE;\n\n\t\tif (ops->pud_entry)\n\t\t\terr = ops->pud_entry(pud, addr, next, walk);\n\t\tif (err)\n\t\t\tbreak;\n\n\t\tif (walk->action == ACTION_AGAIN)\n\t\t\tgoto again;\n\t\tif (walk->action == ACTION_CONTINUE)\n\t\t\tcontinue;\n\n\t\tif (!has_handler) { /* No handlers for lower page tables. */\n\t\t\tif (!has_install)\n\t\t\t\tcontinue; /* Nothing to do. */\n\t\t\t/*\n\t\t\t * We are ONLY installing, so avoid unnecessarily\n\t\t\t * splitting a present huge page.\n\t\t\t */\n\t\t\tif (pud_present(*pud) && pud_trans_huge(*pud))\n\t\t\t\tcontinue;\n\t\t}\n\n\t\tif (walk->vma)\n\t\t\tsplit_huge_pud(walk->vma, pud, addr);\n\t\telse if (pud_leaf(*pud) || !pud_present(*pud))\n\t\t\tcontinue; /* Nothing to do. */\n\n\t\terr = walk_pmd_range(pud, addr, next, walk);\n\t\tif (err)\n\t\t\tbreak;\n\n\t\tif (walk->action == ACTION_AGAIN)\n\t\t\tgoto again;\n\n\t} while (pud++, addr = next, addr != end);\n\n\treturn err;\n}\n\nstatic int walk_p4d_range(pgd_t *pgd, unsigned long addr, unsigned long end,\n\t\t\t  struct mm_walk *walk)\n{\n\tp4d_t *p4d;\n\tunsigned long next;\n\tconst struct mm_walk_ops *ops = walk->ops;\n\tbool has_handler = ops->pud_entry || ops->pmd_entry || ops->pte_entry;\n\tbool has_install = ops->install_pte;\n\tint err = 0;\n\tint depth = real_depth(1);\n\n\tp4d = p4d_offset(pgd, addr);\n\tdo {\n\t\tnext = p4d_addr_end(addr, end);\n\t\tif (p4d_none_or_clear_bad(p4d)) {\n\t\t\tif (has_install)\n\t\t\t\terr = __pud_alloc(walk->mm, p4d, addr);\n\t\t\telse if (ops->pte_hole)\n\t\t\t\terr = ops->pte_hole(addr, next, depth, walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t\tif (!has_install)\n\t\t\t\tcontinue;\n\t\t}\n\t\tif (ops->p4d_entry) {\n\t\t\terr = ops->p4d_entry(p4d, addr, next, walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t}\n\t\tif (has_handler || has_install)\n\t\t\terr = walk_pud_range(p4d, addr, next, walk);\n\t\tif (err)\n\t\t\tbreak;\n\t} while (p4d++, addr = next, addr != end);\n\n\treturn err;\n}\n\nstatic int walk_pgd_range(unsigned long addr, unsigned long end,\n\t\t\t  struct mm_walk *walk)\n{\n\tpgd_t *pgd;\n\tunsigned long next;\n\tconst struct mm_walk_ops *ops = walk->ops;\n\tbool has_handler = ops->p4d_entry || ops->pud_entry || ops->pmd_entry ||\n\t\tops->pte_entry;\n\tbool has_install = ops->install_pte;\n\tint err = 0;\n\n\tif (walk->pgd)\n\t\tpgd = walk->pgd + pgd_index(addr);\n\telse\n\t\tpgd = pgd_offset(walk->mm, addr);\n\tdo {\n\t\tnext = pgd_addr_end(addr, end);\n\t\tif (pgd_none_or_clear_bad(pgd)) {\n\t\t\tif (has_install)\n\t\t\t\terr = __p4d_alloc(walk->mm, pgd, addr);\n\t\t\telse if (ops->pte_hole)\n\t\t\t\terr = ops->pte_hole(addr, next, 0, walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t\tif (!has_install)\n\t\t\t\tcontinue;\n\t\t}\n\t\tif (ops->pgd_entry) {\n\t\t\terr = ops->pgd_entry(pgd, addr, next, walk);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t}\n\t\tif (has_handler || has_install)\n\t\t\terr = walk_p4d_range(pgd, addr, next, walk);\n\t\tif (err)\n\t\t\tbreak;\n\t} while (pgd++, addr = next, addr != end);\n\n\treturn err;\n}\n\n#ifdef CONFIG_HUGETLB_PAGE\nstatic unsigned long hugetlb_entry_end(struct hstate *h, unsigned long addr,\n\t\t\t\t       unsigned long end)\n{\n\tunsigned long boundary = (addr & huge_page_mask(h)) + huge_page_size(h);\n\n\treturn min(boundary, end);\n}\n\nstatic int walk_hugetlb_range(unsigned long addr, unsigned long end,\n\t\t\t      struct mm_walk *walk)\n{\n\tstruct vm_area_struct *vma = walk->vma;\n\tstruct hstate *h = hstate_vma(vma);\n\tunsigned long next;\n\tunsigned long hmask = huge_page_mask(h);\n\tunsigned long sz = huge_page_size(h);\n\tpte_t *pte;\n\tconst struct mm_walk_ops *ops = walk->ops;\n\tint err = 0;\n\n\thugetlb_vma_lock_read(vma);\n\tdo {\n\t\tnext = hugetlb_entry_end(h, addr, end);\n\t\tpte = hugetlb_walk(vma, addr & hmask, sz);\n\t\tif (pte)\n\t\t\terr = ops->hugetlb_entry(pte, hmask, addr, next, walk);\n\t\telse if (ops->pte_hole)\n\t\t\terr = ops->pte_hole(addr, next, -1, walk);\n\t\tif (err)\n\t\t\tbreak;\n\t} while (addr = next, addr != end);\n\thugetlb_vma_unlock_read(vma);\n\n\treturn err;\n}\n\n#else /* CONFIG_HUGETLB_PAGE */\nstatic int walk_hugetlb_range(unsigned long addr, unsigned long end,\n\t\t\t      struct mm_walk *walk)\n{\n\treturn 0;\n}\n\n#endif /* CONFIG_HUGETLB_PAGE */\n\n/*\n * Decide whether we really walk over the current vma on [@start, @end)\n * or skip it via the returned value. Return 0 if we do walk over the\n * current vma, and return 1 if we skip the vma. Negative values means\n * error, where we abort the current walk.\n */\nstatic int walk_page_test(unsigned long start, unsigned long end,\n\t\t\tstruct mm_walk *walk)\n{\n\tstruct vm_area_struct *vma = walk->vma;\n\tconst struct mm_walk_ops *ops = walk->ops;\n\n\tif (ops->test_walk)\n\t\treturn ops->test_walk(start, end, walk);\n\n\t/*\n\t * vma(VM_PFNMAP) doesn't have any valid struct pages behind VM_PFNMAP\n\t * range, so we don't walk over it as we do for normal vmas. However,\n\t * Some callers are interested in handling hole range and they don't\n\t * want to just ignore any single address range. Such users certainly\n\t * define their ->pte_hole() callbacks, so let's delegate them to handle\n\t * vma(VM_PFNMAP).\n\t */\n\tif (vma->vm_flags & VM_PFNMAP) {\n\t\tint err = 1;\n\t\tif (ops->pte_hole)\n\t\t\terr = ops->pte_hole(start, end, -1, walk);\n\t\treturn err ? err : 1;\n\t}\n\treturn 0;\n}\n\nstatic int __walk_page_range(unsigned long start, unsigned long end,\n\t\t\tstruct mm_walk *walk)\n{\n\tint err = 0;\n\tstruct vm_area_struct *vma = walk->vma;\n\tconst struct mm_walk_ops *ops = walk->ops;\n\tbool is_hugetlb = is_vm_hugetlb_page(vma);\n\n\t/* We do not support hugetlb PTE installation. */\n\tif (ops->install_pte && is_hugetlb)\n\t\treturn -EINVAL;\n\n\tif (ops->pre_vma) {\n\t\terr = ops->pre_vma(start, end, walk);\n\t\tif (err)\n\t\t\treturn err;\n\t}\n\n\tif (is_hugetlb) {\n\t\tif (ops->hugetlb_entry)\n\t\t\terr = walk_hugetlb_range(start, end, walk);\n\t} else\n\t\terr = walk_pgd_range(start, end, walk);\n\n\tif (ops->post_vma)\n\t\tops->post_vma(walk);\n\n\treturn err;\n}\n\nstatic inline void process_mm_walk_lock(struct mm_struct *mm,\n\t\t\t\t\tenum page_walk_lock walk_lock)\n{\n\tif (walk_lock == PGWALK_RDLOCK)\n\t\tmmap_assert_locked(mm);\n\telse if (walk_lock != PGWALK_VMA_RDLOCK_VERIFY)\n\t\tmmap_assert_write_locked(mm);\n}\n\nstatic inline int process_vma_walk_lock(struct vm_area_struct *vma,\n\t\t\t\t\t enum page_walk_lock walk_lock)\n{\n#ifdef CONFIG_PER_VMA_LOCK\n\tswitch (walk_lock) {\n\tcase PGWALK_WRLOCK:\n\t\treturn vma_start_write_killable(vma);\n\tcase PGWALK_WRLOCK_VERIFY:\n\t\tvma_assert_write_locked(vma);\n\t\tbreak;\n\tcase PGWALK_VMA_RDLOCK_VERIFY:\n\t\tvma_assert_locked(vma);\n\t\tbreak;\n\tcase PGWALK_RDLOCK:\n\t\t/* PGWALK_RDLOCK is handled by process_mm_walk_lock */\n\t\tbreak;\n\t}\n#endif\n\treturn 0;\n}\n\n/*\n * See the comment for walk_page_range(), this performs the heavy lifting of the\n * operation, only sets no restrictions on how the walk proceeds.\n *\n * We usually restrict the ability to install PTEs, but this functionality is\n * available to internal memory management code and provided in mm/internal.h.\n */\nint walk_page_range_mm_unsafe(struct mm_struct *mm, unsigned long start,\n\t\tunsigned long end, const struct mm_walk_ops *ops,\n\t\tvoid *private)\n{\n\tint err = 0;\n\tunsigned long next;\n\tstruct vm_area_struct *vma;\n\tstruct mm_walk walk = {\n\t\t.ops\t\t= ops,\n\t\t.mm\t\t= mm,\n\t\t.private\t= private,\n\t};\n\n\tif (start >= end)\n\t\treturn -EINVAL;\n\n\tif (!walk.mm)\n\t\treturn -EINVAL;\n\n\tprocess_mm_walk_lock(walk.mm, ops->walk_lock);\n\n\tvma = find_vma(walk.mm, start);\n\tdo {\n\t\tif (!vma) { /* after the last vma */\n\t\t\twalk.vma = NULL;\n\t\t\tnext = end;\n\t\t\tif (ops->pte_hole)\n\t\t\t\terr = ops->pte_hole(start, next, -1, &walk);\n\t\t} else if (start < vma->vm_start) { /* outside vma */\n\t\t\twalk.vma = NULL;\n\t\t\tnext = min(end, vma->vm_start);\n\t\t\tif (ops->pte_hole)\n\t\t\t\terr = ops->pte_hole(start, next, -1, &walk);\n\t\t} else { /* inside vma */\n\t\t\terr = process_vma_walk_lock(vma, ops->walk_lock);\n\t\t\tif (err)\n\t\t\t\tbreak;\n\t\t\twalk.vma = vma;\n\t\t\tnext = min(end, vma->vm_end);\n\t\t\tvma = find_vma(mm, vma->vm_end);\n\n\t\t\terr = walk_page_test(start, next, &walk);\n\t\t\tif (err > 0) {\n\t\t\t\t/*\n\t\t\t\t * positive return values are purely for\n\t\t\t\t * controlling the pagewalk, so should never\n\t\t\t\t * be passed to the callers.\n\t\t\t\t */\n\t\t\t\terr = 0;\n\t\t\t\tcontinue;\n\t\t\t}\n\t\t\tif (err < 0)\n\t\t\t\tbreak;\n\t\t\terr = __walk_page_range(start, next, &walk);\n\t\t}\n\t\tif (err)\n\t\t\tbreak;\n\t} while (start = next, start < end);\n\treturn err;\n}\n\n/*\n * Determine if the walk operations specified are permitted to be used for a\n * page table walk.\n *\n * This check is performed on all functions which are parameterised by walk\n * operations and exposed in include/linux/pagewalk.h.\n *\n * Internal memory management code can use *_unsafe() functions to be able to\n * use all page walking operations.\n */\nstatic bool check_ops_safe(const struct mm_walk_ops *ops)\n{\n\t/*\n\t * The installation of PTEs is solely under the control of memory\n\t * management logic and subject to many subtle locking, security and\n\t * cache considerations so we cannot permit other users to do so, and\n\t * certainly not for exported symbols.\n\t */\n\tif (ops->install_pte)\n\t\treturn false;\n\n\treturn true;\n}\n\n/**\n * walk_page_range - walk page table with caller specific callbacks\n * @mm:\t\tmm_struct representing the target process of page table walk\n * @start:\tstart address of the virtual address range\n * @end:\tend address of the virtual address range\n * @ops:\toperation to call during the walk\n * @private:\tprivate data for callbacks' usage\n *\n * Recursively walk the page table tree of the process represented by @mm\n * within the virtual address range [@start, @end). During walking, we can do\n * some caller-specific works for each entry, by setting up pmd_entry(),\n * pte_entry(), and/or hugetlb_entry(). If you don't set up for some of these\n * callbacks, the associated entries/pages are just ignored.\n * The return values of these callbacks are commonly defined like below:\n *\n *  - 0  : succeeded to handle the current entry, and if you don't reach the\n *         end address yet, continue to walk.\n *  - >0 : succeeded to handle the current entry, and return to the caller\n *         with caller specific value.\n *  - <0 : failed to handle the current entry, and return to the caller\n *         with error code.\n *\n * Before starting to walk page table, some callers want to check whether\n * they really want to walk over the current vma, typically by checking\n * its vm_flags. walk_page_test() and @ops->test_walk() are used for this\n * purpose.\n *\n * If operations need to be staged before and committed after a vma is walked,\n * there are two callbacks, pre_vma() and post_vma(). Note that post_vma(),\n * since it is intended to handle commit-type operations, can't return any\n * errors.\n *\n * struct mm_walk keeps current values of some common data like vma and pmd,\n * which are useful for the access from callbacks. If you want to pass some\n * caller-specific data to callbacks, @private should be helpful.\n *\n * Locking:\n *   Callers of walk_page_range() and walk_page_vma() should hold @mm->mmap_lock,\n *   because these function traverse vma list and/or access to vma's data.\n */\nint walk_page_range(struct mm_struct *mm, unsigned long start,\n\t\tunsigned long end, const struct mm_walk_ops *ops,\n\t\tvoid *private)\n{\n\tif (!check_ops_safe(ops))\n\t\treturn -EINVAL;\n\n\treturn walk_page_range_mm_unsafe(mm, start, end, ops, private);\n}\n\n/**\n * walk_kernel_page_table_range - walk a range of kernel pagetables.\n * @start:\tstart address of the virtual address range\n * @end:\tend address of the virtual address range\n * @ops:\toperation to call during the walk\n * @pgd:\tpgd to walk if different from mm->pgd\n * @private:\tprivate data for callbacks' usage\n *\n * Similar to walk_page_range() but can walk any page tables even if they are\n * not backed by VMAs. Because 'unusual' entries may be walked this function\n * will also not lock the PTEs for the pte_entry() callback. This is useful for\n * walking kernel pages tables or page tables for firmware.\n *\n * Note: Be careful to walk the kernel pages tables, the caller may be need to\n * take other effective approaches (mmap lock may be insufficient) to prevent\n * the intermediate kernel page tables belonging to the specified address range\n * from being freed (e.g. memory hot-remove).\n */\nint walk_kernel_page_table_range(unsigned long start, unsigned long end,\n\t\tconst struct mm_walk_ops *ops, pgd_t *pgd, void *private)\n{\n\t/*\n\t * Kernel intermediate page tables are usually not freed, so the mmap\n\t * read lock is sufficient. But there are some exceptions.\n\t * E.g. memory hot-remove. In which case, the mmap lock is insufficient\n\t * to prevent the intermediate kernel pages tables belonging to the\n\t * specified address range from being freed. The caller should take\n\t * other actions to prevent this race.\n\t */\n\tmmap_assert_locked(&init_mm);\n\n\treturn walk_kernel_page_table_range_lockless(start, end, ops, pgd,\n\t\t\t\t\t\t     private);\n}\n\n/*\n * Use this function to walk the kernel page tables locklessly. It should be\n * guaranteed that the caller has exclusive access over the range they are\n * operating on - that there should be no concurrent access, for example,\n * changing permissions for vmalloc objects.\n */\nint walk_kernel_page_table_range_lockless(unsigned long start, unsigned long end,\n\t\tconst struct mm_walk_ops *ops, pgd_t *pgd, void *private)\n{\n\tstruct mm_walk walk = {\n\t\t.ops\t\t= ops,\n\t\t.mm\t\t= &init_mm,\n\t\t.pgd\t\t= pgd,\n\t\t.private\t= private,\n\t\t.no_vma\t\t= true\n\t};\n\n\tif (start >= end)\n\t\treturn -EINVAL;\n\tif (!check_ops_safe(ops))\n\t\treturn -EINVAL;\n\n\treturn walk_pgd_range(start, end, &walk);\n}\n\n/**\n * walk_page_range_debug - walk a range of pagetables not backed by a vma\n * @mm:\t\tmm_struct representing the target process of page table walk\n * @start:\tstart address of the virtual address range\n * @end:\tend address of the virtual address range\n * @ops:\toperation to call during the walk