    "content": "{"content":" * >0 - this number of misplaced folios could not be queued for moving\n *      (a hugetlbfs page or a transparent huge page being counted as 1).\n * -EIO - a misplaced page found, when MPOL_MF_STRICT specified without MOVEs.\n * -EFAULT - a hole in the memory range, when MPOL_MF_DISCONTIG_OK unspecified.\n * -EINTR - walk got terminated due to pending fatal signal.\n */\nstatic long\nqueue_pages_range(struct mm_struct *mm, unsigned long start, unsigned long end,\n\t\tnodemask_t *nodes, unsigned long flags,\n\t\tstruct list_head *pagelist)\n{\n\tint err;\n\tstruct queue_pages qp = {\n\t\t.pagelist = pagelist,\n\t\t.flags = flags,\n\t\t.nmask = nodes,\n\t\t.start = start,\n\t\t.end = end,\n\t\t.first = NULL,\n\t};\n\tconst struct mm_walk_ops *ops = (flags & MPOL_MF_WRLOCK) ?\n\t\t\t&queue_pages_lock_vma_walk_ops : &queue_pages_walk_ops;\n\n\terr = walk_page_range(mm, start, end, ops, &qp);\n\n\tif (!qp.first)\n\t\t/* whole range in hole */\n\t\terr = -EFAULT;\n\n\treturn err ? : qp.nr_failed;\n}\n\n/*\n * Apply policy to a single VMA\n * This must be called with the mmap_lock held for writing.\n */\nstatic int vma_replace_policy(struct vm_area_struct *vma,\n\t\t\t\tstruct mempolicy *pol)\n{\n\tint err;\n\tstruct mempolicy *old;\n\tstruct mempolicy *new;\n\n\tvma_assert_write_locked(vma);\n\n\tnew = mpol_dup(pol);\n\tif (IS_ERR(new))\n\t\treturn PTR_ERR(new);\n\n\tif (vma->vm_ops && vma->vm_ops->set_policy) {\n\t\terr = vma->vm_ops->set_policy(vma, new);\n\t\tif (err)\n\t\t\tgoto err_out;\n\t}\n\n\told = vma->vm_policy;\n\tvma->vm_policy = new; /* protected by mmap_lock */\n\tmpol_put(old);\n\n\treturn 0;\n err_out:\n\tmpol_put(new);\n\treturn err;\n}\n\n/* Split or merge the VMA (if required) and apply the new policy */\nstatic int mbind_range(struct vma_iterator *vmi, struct vm_area_struct *vma,\n\t\tstruct vm_area_struct **prev, unsigned long start,\n\t\tunsigned long end, struct mempolicy *new_pol)\n{\n\tunsigned long vmstart, vmend;\n\n\tvmend = min(end, vma->vm_end);\n\tif (start > vma->vm_start) {\n\t\t*prev = vma;\n\t\tvmstart = start;\n\t} else {\n\t\tvmstart = vma->vm_start;\n\t}\n\n\tif (mpol_equal(vma->vm_policy, new_pol)) {\n\t\t*prev = vma;\n\t\treturn 0;\n\t}\n\n\tvma =  vma_modify_policy(vmi, *prev, vma, vmstart, vmend, new_pol);\n\tif (IS_ERR(vma))\n\t\treturn PTR_ERR(vma);\n\n\t*prev = vma;\n\treturn vma_replace_policy(vma, new_pol);\n}\n\n/* Set the process memory policy */\nstatic long do_set_mempolicy(unsigned short mode, unsigned short flags,\n\t\t\t     nodemask_t *nodes)\n{\n\tstruct mempolicy *new, *old;\n\tNODEMASK_SCRATCH(scratch);\n\tint ret;\n\n\tif (!scratch)\n\t\treturn -ENOMEM;\n\n\tnew = mpol_new(mode, flags, nodes);\n\tif (IS_ERR(new)) {\n\t\tret = PTR_ERR(new);\n\t\tgoto out;\n\t}\n\n\ttask_lock(current);\n\tret = mpol_set_nodemask(new, nodes, scratch);\n\tif (ret) {\n\t\ttask_unlock(current);\n\t\tmpol_put(new);\n\t\tgoto out;\n\t}\n\n\told = current->mempolicy;\n\tcurrent->mempolicy = new;\n\tif (new && (new->mode == MPOL_INTERLEAVE ||\n\t\t    new->mode == MPOL_WEIGHTED_INTERLEAVE)) {\n\t\tcurrent->il_prev = MAX_NUMNODES-1;\n\t\tcurrent->il_weight = 0;\n\t}\n\ttask_unlock(current);\n\tmpol_put(old);\n\tret = 0;\nout:\n\tNODEMASK_SCRATCH_FREE(scratch);\n\treturn ret;\n}\n\n/*\n * Return nodemask for policy for get_mempolicy() query\n *\n * Called with task's alloc_lock held\n */\nstatic void get_policy_nodemask(struct mempolicy *pol, nodemask_t *nodes)\n{\n\tnodes_clear(*nodes);\n\tif (pol == &default_policy)\n\t\treturn;\n\n\tswitch (pol->mode) {\n\tcase MPOL_BIND:\n\tcase MPOL_INTERLEAVE:\n\tcase MPOL_PREFERRED:\n\tcase MPOL_PREFERRED_MANY:\n\tcase MPOL_WEIGHTED_INTERLEAVE:\n\t\t*nodes = pol->nodes;\n\t\tbreak;\n\tcase MPOL_LOCAL:\n\t\t/* return empty node mask for local allocation */\n\t\tbreak;\n\tdefault:\n\t\tBUG();\n\t}\n}\n\nstatic int lookup_node(struct mm_struct *mm, unsigned long addr)\n{\n\tstruct page *p = NULL;\n\tint ret;\n\n\tret = get_user_pages_fa